import './Chip.scss';

import type { NewDropdownMenuProps } from ':components/NewDropdownMenu';
import { NewDropdownMenu } from ':components/NewDropdownMenu';
import { PopoverContext } from ':components/Popover';
import { DropDownContent } from ':components/Select/components/DropDownContent';
import { useOverflowText } from ':components/Select/components/hooks/useOverflowText';
import { OverflowCount } from ':components/Select/components/OverflowCount';
import { defaultMakeOption, defaultRenderValue } from ':components/Select/helpers';
import { Tooltip } from ':components/Tooltip';
import { classNames } from ':helpers/classnames';
import React, {
	cloneElement,
	forwardRef,
	isValidElement,
	useEffect,
	useImperativeHandle,
	useMemo,
	useRef,
	useState,
} from 'react';

import { Typography } from '../Typography';
import type { ChipProps } from './Chip.types';
import { useChip } from './useChip';

export const Chip = forwardRef<HTMLButtonElement, ChipProps>(
	<T = any>(
		{
			values,
			label,
			active = false,
			disabled = false,
			dragged = false,
			multiple,
			filter,
			filterPlaceholder = 'Поиск',
			filterFunction,
			onClick,
			className,
			rootClassName,
			startAdornment,
			endAdornment,
			isOpen = false,
			onOutsideClick,
			onOpen,
			onClose,
			onEscape,
			onBlur,
			options = [],
			onSelect,
			dropdownElementID,
			dropdownClassName,
			dataTestId = 'Chip',
			selectAll = false,
			selectAllText = 'Выбрать все',
			onManualClickOption,
			loading,
			loadingText,
			loadingContent,
			makeOption,
			renderValue,
			showTooltip,
			noOptionsText = 'Нет результатов',
			enableKeyboardNavigation = false,
			isShowCountOfValues = false,
			isSelectMode = false,
			applicationRootElementID,
			overlayScroll = true,
			shouldRenderOverlay,
			overlayClassName,
			alignDropDown,
			...props
		}: ChipProps<T>,
		ref,
	) => {
		const {
			chipRef,
			dropdownOpen,
			setDropdownOpen,
			handleClickOutside,
			selectClassName,
			privateValues,
			privateOptions,
			filterValue,
			optionsClassName,
			itemClassName,
			onMultiselectItem,
			onSelectItem,
			focusedIndex,
			handleSelectAll,
			optionsRef,
			getSelectAllStatus,
			filterRef,
			changeFilterValue,
			selectRef,
			handleOpen,
		} = useChip({
			isOpen,
			options,
			values,
			isSelectMode,
			onOpen,
			onClose,
			onOutsideClick,
			onSelect,
			filter,
			filterFunction,
			enableKeyboardNavigation,
			multiple,
			selectAll,
		});

		const counterWrapperRef = useRef<HTMLDivElement>(null);
		useImperativeHandle(ref, () => chipRef?.current);

		const selectAllIndex = -2;

		const [disableTooltip, setDisableTooltip] = useState(true);

		useEffect(() => {
			const shouldDisableTooltip = showTooltip ? chipRef?.current?.offsetWidth >= chipRef?.current?.scrollWidth : true;
			setDisableTooltip(shouldDisableTooltip);
		}, [chipRef, renderValue, values, showTooltip]);

		const dropdownMenuProps: NewDropdownMenuProps = {
			targetElement: chipRef,
			align: alignDropDown,
			verticalOffset: 1,
			applicationRootElementID,
			dropdownElementID,
			className: dropdownClassName,
			onBlur,
			isOpen: dropdownOpen,
			handleSetOpen: setDropdownOpen,
			onOutsideClick: handleClickOutside,
			overlayScroll,
			shouldRenderOverlay,
			overlayClassName,
		};

		const rootWrapClassName = classNames(selectClassName, Boolean(rootClassName) && rootClassName);
		const popoverContextValue = useMemo(
			() => ({
				applicationRootElementId: 'root',
				popoverRootElementID: 'chip-popover',
			}),
			[],
		);

		const hiddenRef = useRef<HTMLParagraphElement>(null);
		const countRef = useRef<HTMLParagraphElement>(null);
		const { count, className: overflowClassName } = useOverflowText({
			hiddenRef,
			inputRef: counterWrapperRef,
		});

		const selectedLabel = renderValue ? renderValue(values) : defaultRenderValue<T>(values);

		const counter = (
			<span className={classNames(overflowClassName, 'static')} ref={countRef}>
				(+{count})
			</span>
		);

		const handleClick = (event: React.MouseEvent<HTMLButtonElement>) => {
			if (isSelectMode) {
				handleOpen?.();
			} else {
				onClick?.(event);
			}
		};

		return (
			<div className={rootWrapClassName} data-testid={dataTestId}>
				<PopoverContext.Provider value={popoverContextValue}>
					<Tooltip title={selectedLabel} disableHover={disableTooltip}>
						<button
							data-testid="Chip-button"
							tabIndex={onClick ? 0 : -1}
							aria-pressed={!!onClick}
							onClick={disabled ? undefined : handleClick}
							disabled={disabled}
							className={classNames(
								'dsb_chip',
								active && 'dsb_chip--active',
								disabled && 'dsb_chip--disabled',
								startAdornment && 'dsb_chip--start-icon',
								endAdornment && 'dsb_chip--end-icon',
								onClick && 'dsb_chip--clickable',
								dragged && 'dsb_chip--dragged',
								multiple && 'dsb_chip--multiple',
								className,
							)}
							{...props}
							ref={chipRef}
						>
							{startAdornment && (
								<div className="dsb_chip__adornment dsb_chip__start-icon">
									{isValidElement(startAdornment)
										? cloneElement<any>(startAdornment, {
												size: 'small',
											})
										: startAdornment}
								</div>
							)}

							<div ref={counterWrapperRef} className={classNames(multiple && 'dsb_chip--multiple', 'ellipsis')}>
								<Typography variant="body3" className="dsb_chip__title">
									{selectedLabel || label}
								</Typography>

								{isSelectMode && isShowCountOfValues && (
									<OverflowCount
										inputRef={counterWrapperRef}
										hiddenRef={hiddenRef}
										values={values}
										countRef={countRef}
									/>
								)}
							</div>

							{isSelectMode && isShowCountOfValues && counter}

							{endAdornment && (
								<div className="dsb_chip__adornment dsb_chip__end-icon">
									{isValidElement(endAdornment)
										? cloneElement<any>(endAdornment, {
												size: 'small',
											})
										: endAdornment}
								</div>
							)}
						</button>
					</Tooltip>
				</PopoverContext.Provider>

				{isSelectMode && dropdownOpen && (
					<NewDropdownMenu {...dropdownMenuProps}>
						<DropDownContent
							selectedItems={privateValues}
							optionsData={privateOptions}
							selectAll={selectAll}
							filter={filter}
							filterValue={filterValue}
							filterFunction={filterFunction}
							selectAllIndex={selectAllIndex}
							optionsClassName={optionsClassName}
							multiple={multiple}
							itemClassName={itemClassName}
							onMultiselectItem={onMultiselectItem}
							onManualClickOption={onManualClickOption}
							onSelectItem={onSelectItem}
							focusedIndex={focusedIndex}
							handleSelectAll={handleSelectAll}
							makeOption={makeOption}
							showTooltip={showTooltip}
							defaultMakeOption={defaultMakeOption}
							selectAllText={selectAllText}
							loading={loading}
							loadingText={loadingText} // TODO: удалить
							loadingContent={loadingContent}
							noOptionsText={noOptionsText}
							optionsRef={optionsRef}
							selectStatus={getSelectAllStatus()}
							filterPlaceholder={filterPlaceholder}
							filterRef={filterRef}
							changeFilterValue={changeFilterValue}
							dataTestId={dataTestId}
							selectRef={selectRef}
						/>
					</NewDropdownMenu>
				)}
			</div>
		);
	},
);
